class TestHappyPath:
    def test_single_character(self):
        assert run_length_encode("a") == [("a", 1)]

    def test_all_same_characters(self):
        assert run_length_encode("aaaa") == [("a", 4)]

    def test_no_consecutive_repeats(self):
        assert run_length_encode("abcd") == [("a", 1), ("b", 1), ("c", 1), ("d", 1)]

    def test_mixed_runs(self):
        assert run_length_encode("aabbbcc") == [("a", 2), ("b", 3), ("c", 2)]

    def test_two_character_alternating(self):
        assert run_length_encode("ababab") == [
            ("a", 1), ("b", 1), ("a", 1), ("b", 1), ("a", 1), ("b", 1)
        ]

    def test_run_at_end(self):
        assert run_length_encode("abccc") == [("a", 1), ("b", 1), ("c", 3)]

    def test_run_at_start(self):
        assert run_length_encode("aaab") == [("a", 3), ("b", 1)]

    def test_two_distinct_runs(self):
        assert run_length_encode("aabb") == [("a", 2), ("b", 2)]

    def test_numeric_characters(self):
        assert run_length_encode("11223") == [("1", 2), ("2", 2), ("3", 1)]

    def test_special_characters(self):
        assert run_length_encode("!!??##") == [("!", 2), ("?", 2), ("#", 2)]

    def test_whitespace_characters(self):
        assert run_length_encode("a  b") == [("a", 1), (" ", 2), ("b", 1)]

    def test_mixed_character_types(self):
        assert run_length_encode("aA") == [("a", 1), ("A", 1)]

    def test_long_single_run(self):
        assert run_length_encode("z" * 1000) == [("z", 1000)]

    def test_returns_list(self):
        result = run_length_encode("abc")
        assert isinstance(result, list)

    def test_each_element_is_tuple(self):
        result = run_length_encode("aabb")
        assert all(isinstance(item, tuple) for item in result)

    def test_each_tuple_has_two_elements(self):
        result = run_length_encode("aabb")
        assert all(len(item) == 2 for item in result)


